#include<bits/stdc++.h>
using namespace std;
const int Maxnb = 1e5 + 5;
int n, b, i, j, maxsteps = 1, last[Maxnb], Next[Maxnb];
bool Get[Maxnb];
struct snow {
	int snowdeep,sloc;
} f[Maxnb];
struct bost {
	int bostdeep, dis, bloc;
} s[Maxnb];
bool compsnow (snow a, snow b) {
	return a.snowdeep < b.snowdeep;
}
bool compbost (bost a, bost b) {
	return a.bostdeep < b.bostdeep;
}
int main() {
	memset (Get, 0, sizeof (Get));
	cin >> n >> b;
	for (int i = 1; i <= n; i++) {
		cin >> f[i].snowdeep;
		f[i].sloc = i;
	}
	for (int i = 1; i <= b; i++) {
		cin >> s[i].bostdeep >> s[i].dis;
		s[i].bloc = i;
	}
	sort (f + 1, f + n + 1, compsnow);
	sort (s + 1, s + b + 1,compbost);
	for (i = 1; i <= n; ++i) {
		last[i] = i - 1;
		Next[i] = i + 1;
	}
	j = n; 
	for (i = b; i >= 1; --i) {
		while (j >= 1 && f[j].snowdeep > s[i].bostdeep) {
		    last[Next[f[j].sloc]]=last[f[j].sloc];
		    Next[last[f[j].sloc]]=Next[f[j].sloc];
		    maxsteps = max (maxsteps, Next[f[j].sloc] - last[f[j].sloc]);
		    j--;
		}
		Get[s[i].bloc] = (s[i].dis >= maxsteps);
	}
	for (i = 1; i <= b; ++i) {
		cout << Get[i] << '\n';
	}
	return 0;
}
